exercises.solution_code:
#include <cstddef>
#include <iostream>

int main()
{
    constexpr std::size_t rows{ 3 };
    constexpr std::size_t cols{ 4 };
    int matrix[rows][cols]{};

    for (std::size_t r{ 0 }; r < rows; ++r)
        for (std::size_t c{ 0 }; c < cols; ++c)
            std::cin >> matrix[r][c];

    for (std::size_t r{ 0 }; r < rows; ++r)
    {
        int rowSum{ 0 };
        for (std::size_t c{ 0 }; c < cols; ++c)
            rowSum += matrix[r][c];
        std::cout << rowSum << '\n';
    }

    return 0;
}

